<?php
 namespace League\CommonMark\Block\Element; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; use League\CommonMark\Node\Node; abstract class AbstractBlock extends Node { public $data = []; protected $open = true; protected $lastLineBlank = false; protected $startLine = 0; protected $endLine = 0; protected function setParent(Node $node = null) { if ($node && !$node instanceof self) { throw new \InvalidArgumentException('Parent of block must also be block (can not be inline)'); } parent::setParent($node); } public function isContainer(): bool { return true; } public function hasChildren(): bool { return $this->firstChild !== null; } abstract public function canContain(AbstractBlock $block): bool; abstract public function isCode(): bool; abstract public function matchesNextLine(Cursor $cursor): bool; public function setStartLine(int $startLine) { $this->startLine = $startLine; if (empty($this->endLine)) { $this->endLine = $startLine; } return $this; } public function getStartLine(): int { return $this->startLine; } public function setEndLine(int $endLine) { $this->endLine = $endLine; return $this; } public function getEndLine(): int { return $this->endLine; } public function endsWithBlankLine(): bool { return $this->lastLineBlank; } public function setLastLineBlank(bool $blank) { $this->lastLineBlank = $blank; } public function shouldLastLineBeBlank(Cursor $cursor, int $currentLineNumber): bool { return $cursor->isBlank(); } public function isOpen(): bool { return $this->open; } public function finalize(ContextInterface $context, int $endLineNumber) { if (!$this->open) { return; } $this->open = false; $this->endLine = $endLineNumber; if ($context->getTip() !== null) { $context->setTip($context->getTip()->parent()); } } public function getData(string $key, $default = null) { return \array_key_exists($key, $this->data) ? $this->data[$key] : $default; } } 